import ast


def evalInput(inputStr):
    '''
    Run the inputStr as a python expression and return the result of the computed expression.
    '''
    if not isinstance(inputStr, str):
        raise TypeError()
    expr = inputStr.strip()
    if expr == '' or len(expr) > 200:
        raise ValueError()

    try:
        node = ast.parse(expr, mode='eval')
    except Exception as e:
        raise ValueError() from e

    # Allow only numeric expressions with +,-,*,/, parentheses and unary +/-
    allowed_nodes = (
        ast.Expression, ast.BinOp, ast.UnaryOp, ast.Num, ast.Constant,
        ast.Add, ast.Sub, ast.Mult, ast.Div, ast.Mod, ast.Pow,
        ast.USub, ast.UAdd, ast.FloorDiv,
        ast.Load, ast.Tuple, ast.List
    )

    for n in ast.walk(node):
        if not isinstance(n, allowed_nodes):
            raise ValueError()
        if isinstance(n, ast.Constant):
            if not isinstance(n.value, (int, float)):
                raise ValueError()

