def getFibonacci(n):
    '''
    Compute the n-th fibonacci number using loops only.
    '''
    if not isinstance(n, int):
        raise TypeError()
    if n <= 0:
        raise ValueError()
    if n <= 2:
        return 1

    a, b = 1, 1
    i = 2
    while i < n:
        a, b = b, a + b
        i += 1
    return b

